import{_ as t,o as r,c as d,a3 as o}from"./chunks/framework.DG2GXa4n.js";const f=JSON.parse('{"title":"Миграция","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/migration.md","filePath":"ru/guide/migration.md","lastUpdated":1781015796000}'),c={name:"ru/guide/migration.md"};function a(n,e,i,l,s,u){return r(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="миграция" tabindex="-1">Миграция <a class="header-anchor" href="#миграция" aria-label="Permalink to &quot;Миграция&quot;">​</a></h1><h2 id="с-farfetched" tabindex="-1">С farfetched <a class="header-anchor" href="#с-farfetched" aria-label="Permalink to &quot;С farfetched&quot;">​</a></h2><p>Модель близка, поэтому большая часть кода переносится напрямую. Главный сдвиг: <strong>приносите свой эффект</strong>, а inline-опции доступны наравне с операторами.</p><table tabindex="0"><thead><tr><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td><code>createQuery({ handler })</code></td><td><code>createQuery({ effect })</code> (или <code>{ handler }</code>)</td></tr><tr><td><code>createJsonQuery({ ... })</code></td><td><code>createJsonQuery({ request, response })</code></td></tr><tr><td><code>retry(query, { times, delay })</code></td><td><code>retry(query, …)</code> <strong>или</strong> inline <code>createQuery({ retry })</code></td></tr><tr><td><code>cache(query, { ... })</code></td><td><code>cache(query, …)</code> <strong>или</strong> inline <code>createQuery({ cache })</code></td></tr><tr><td><code>concurrency(query, { strategy })</code></td><td><code>concurrency(query, …)</code> <strong>или</strong> inline <code>createQuery({ concurrency })</code></td></tr><tr><td><code>connectQuery({ source, fn, target })</code></td><td>идентично</td></tr><tr><td><code>createMutation</code></td><td><code>createMutation</code> (+ алиас <code>mutate</code>)</td></tr><tr><td>контракты</td><td><code>zodContract</code> / <code>standardSchemaContract</code> / <code>createContract</code></td></tr><tr><td><code>$data / $error / $status / $pending</code></td><td>те же имена</td></tr></tbody></table><p>Заметные отличия:</p><ul><li>Query оборачивает <strong>реальный эффект</strong> (<code>query.__.effect</code>), видимый в devtools.</li><li>Отмена реальная для эффектов из <code>createRequestFx</code> (AbortSignal), а не только discard.</li><li>Sourced-конфиг доступен inline (<code>Store</code> для <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code> / <code>enabled</code>).</li><li><code>useUnit(query)</code> работает напрямую в React и Vue через <code>@@unitShape</code>.</li></ul><p>Чего пока нет (в сравнении с farfetched): биндинг Solid, полная sourced-поверхность на каждом поле и часть удобств JSON-контрактов. См. <a href="https://github.com/Olovyannikov/effector-query/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">roadmap</a>.</p><h2 id="внутри-0-x" tabindex="-1">Внутри 0.x <a class="header-anchor" href="#внутри-0-x" aria-label="Permalink to &quot;Внутри 0.x&quot;">​</a></h2><p>До 1.0 API ещё может меняться между минорными версиями; ломающие изменения отмечаются в changelog. Из заметного:</p><ul><li>Адаптеры web-storage теперь принимают <strong>объект опций</strong>: <code>localStorageCache({ version, maxAge })</code> (раньше — строку-префикс).</li></ul>',10)])])}const g=t(c,[["render",a]]);export{f as __pageData,g as default};
